import{_ as t,o as r,c as p,j as a,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const T=JSON.parse('{"title":"开发者对谈2：青梅煮酒","description":"","frontmatter":{},"headers":[],"relativePath":"6.STG/6.6.开发者访谈/开发者对谈2：青梅煮酒.md","filePath":"6.STG/6.6.开发者访谈/开发者对谈2：青梅煮酒.md"}'),o={name:"6.STG/6.6.开发者访谈/开发者对谈2：青梅煮酒.md"};function _(d,e,l,i,c,h){return r(),p("div",null,[...e[0]||(e[0]=[a("h1",{id:"开发者对谈2-青梅煮酒",tabindex:"-1"},[n("开发者对谈2：青梅煮酒 "),a("a",{class:"header-anchor",href:"#开发者对谈2-青梅煮酒","aria-label":'Permalink to "开发者对谈2：青梅煮酒"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),s('<h1 id="开发者对谈2-青梅煮酒-1" tabindex="-1">开发者对谈2：青梅煮酒 <a class="header-anchor" href="#开发者对谈2-青梅煮酒-1" aria-label="Permalink to &quot;开发者对谈2：青梅煮酒&quot;">​</a></h1><p>开发者对谈2：青梅煮酒</p><p>一日，TMD审核组有人遥指天外龙挂，战车与高塔凭栏观之。战车曰：“使君知撰写之变化否？”高塔曰：“未知其详。”战车曰：“撰写能强能弱，能硬能软；强则做操越级，弱则亏特负面；硬则如agito飞腾于宇宙之间，软则如人格面具潜伏于黑盒之内。方今春深，撰写乘时变化，犹人得志而纵横四海。撰写之为物，可比世之英雄。高塔久历四方，必知当世撰写英雄。请试指言之。”</p><p>战车：星星，应该是结合撰写和画风相当不错，虽然有时候会为实用性让画风妥协以及用力过猛。但要我说的话是中流砥柱的范畴。</p><p>力量：我写的资源讲究一个查无此人。</p><p>战车：我觉得还好，写资源的时候有种希望它应有尽有的感觉，然后就是撰写的风格有点激进（或者说功利）。</p><p>车战：今日魔刀被锐评，我心死，疯狂。</p><p>战车：我很喜欢，因为你写的资源在我看来能很明显的感觉到其中有它本身所属的意或者神，这是很难得的。接着是强度方面，我的评价是比较激进，你倾向于写出的资源更有强度（所以有时候搞的我很蛋疼）。</p><p>魔恶：我呢？</p><p>战车：说实话现在还不能看出来，因为你写资源的时间较短，大部分新人在这个阶段（指了解撰写大部分写法）写的资源都会倾向功利（我最功利的资源也是这个阶段写的），因此你的写法还没得定型。接着是我当前对你写法的印象：偏激进，但会试着接近自己想要的画风。</p><p>战车：顺带肘一下恶魔，我不是很喜欢恶魔这个人，但是我得说，你的资源和你这个人可以分开看，尽管你想写（或者口嗨）出一些不受控制的资源，但是你当前写在书上的资源，是偏保守以及对于画风较为看重的，在我看来是没有大问题的。</p><p>人恋：我写的东西.....</p><p>战车：你不需要妄自菲薄，你的撰写风格是我很欣赏的。暴怒行者是我很喜欢的资源，写法上保守，但是在保守的立场上，有写出你认为应该获得的东西（也就是有亏有赚）。你的写法（以及审核资源的态度）在我看来是很难得一见的。</p><p>（有人投入了一个大资源，讨论无疾而终）</p><p>隐者：？，我打个游戏的时候错过了什么！</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const b=t(o,[["render",_]]);export{T as __pageData,b as default};
